#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int max(int a, int b) {
    return (a > b) ? a : b;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* arr = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int* dp = (int*) malloc(N * sizeof(int));
        dp[0] = 1;
        for (int i = 1; i < N; i++) {
            dp[i] = 1;
            for (int j = 0; j < i; j++) {
                if (gcd(arr[i], arr[j]) > 1) {
                    dp[i] = max(dp[i], dp[j] + 1);
                }
            }
        }
        int max_val = 0;
        for (int i = 0; i < N; i++) {
            max_val = max(max_val, dp[i]);
        }
        printf("%d\n", max_val);
        free(arr);
        free(dp);
    }
    return 0;
}

