import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            int[] dp = new int[N];
            dp[0] = 1;
            for (int i = 1; i < N; i++) {
                dp[i] = 1;
                for (int j = 0; j < i; j++) {
                    if (gcd(arr[i], arr[j]) > 1) {
                        dp[i] = Math.max(dp[i], dp[j] + 1);
                    }
                }
            }
            int max_val = 0;
            for (int i = 0; i < N; i++) {
                max_val = Math.max(max_val, dp[i]);
            }
            System.out.println(max_val);
        }
    }
}

