import math

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def main():
    T = int(input())
    for _ in range(T):
        N = int(input())
        arr = list(map(int, input().split()))
        dp = [1] * N
        for i in range(1, N):
            for j in range(i):
                if gcd(arr[i], arr[j]) > 1:
                    dp[i] = max(dp[i], dp[j] + 1)
        print(max(dp))

